import ReactMarkdown, { Components, ExtraProps } from 'react-markdown';
import dynamic from 'next/dynamic';
import RssFeedWidget from '@/components/RssFeedWidget';
import KatexStyles from '@/components/KatexStyles';
import remarkGfm from 'remark-gfm';
import rehypeRaw from 'rehype-raw';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import rehypeSlug from 'rehype-slug';
import rehypeImageMetadata from '@/lib/rehype-image-metadata';
import { siteConfig } from '../../site.config';
import remarkWikilinks from '@/lib/remark-wikilinks';
import ExportedImage from 'next-image-export-optimizer';
import { PluggableList } from 'unified';
import type { SlugRegistryEntry } from '@/lib/markdown';

// Lazy-loaded: Mermaid is ~1.5 MB minified; only pages with diagrams pay the cost.
const Mermaid = dynamic(() => import('@/components/Mermaid'), { ssr: false });
// Lazy-loaded: splits the syntax-highlighter chunk out of every post page bundle.
const CodeBlock = dynamic(() => import('@/components/CodeBlock'));

interface MarkdownRendererProps {
  content: string;
  latex?: boolean;
  slug?: string;
  slugRegistry?: Map<string, SlugRegistryEntry>;
}

export default function MarkdownRenderer({ content, latex = false, slug, slugRegistry }: MarkdownRendererProps) {
  const remarkPlugins: PluggableList = [remarkGfm];
  const cdnBaseUrl = siteConfig.images?.cdnBaseUrl ?? '';
  const rehypePlugins: PluggableList = [rehypeRaw, rehypeSlug, [rehypeImageMetadata, { slug, cdnBaseUrl }]];

  if (slugRegistry && slugRegistry.size > 0) {
    remarkPlugins.push([remarkWikilinks, { slugRegistry }]);
  }

  if (latex) {
    remarkPlugins.push(remarkMath);
    rehypePlugins.push(rehypeKatex);
  }

  const components: Components = {
    // Use 'p' by default, but fallback to 'div' only if children contain block elements
    // to avoid invalid HTML nesting warnings while preserving semantics.
    p: ({ children }) => {
      // Check if any child is a block-level element (like Mermaid or CodeBlock)
      // Since children is a ReactNode, we can only do a shallow check here.
      // Simple heuristic: if any child is not a string/number, it *might* be a block.
      // However, react-markdown usually nests blocks at the top level.
      return <p className="mb-4 leading-relaxed text-foreground">{children}</p>;
    },
    // Explicitly style lists to ensure contrast
    li: ({ children }) => <li className="text-foreground">{children}</li>,
    // Explicitly style blockquotes
    blockquote: ({ children }) => <blockquote className="text-foreground border-l-accent italic">{children}</blockquote>,
    // Explicitly style bold text
    strong: ({ children }) => <strong className="text-heading font-semibold">{children}</strong>,
    // Wrap tables in a scrollable container
    table: (props) => {
      // eslint-disable-next-line @typescript-eslint/no-unused-vars
      const { children, node: _node, ...rest } = props as React.TableHTMLAttributes<HTMLTableElement> & ExtraProps;
      return (
        <div className="overflow-x-auto my-8 border border-muted/20 rounded-lg">
          <table {...rest} className="min-w-full text-left text-sm">
            {children}
          </table>
        </div>
      );
    },
    // Render 'pre' as a 'div' to allow block-level children
    pre: ({ children }) => <div className="not-prose w-full min-w-0 max-w-full">{children}</div>,
    // Style links individually to avoid hover-all issue
    a: (props) => {
      // eslint-disable-next-line @typescript-eslint/no-unused-vars
      const { node: _node, className, ...rest } = props as React.AnchorHTMLAttributes<HTMLAnchorElement> & ExtraProps;
      // Preserve wikilink classes injected by remark-wikilinks — they have their own CSS styling
      if (className?.includes('wikilink')) {
        return <a {...rest} className={className} />;
      }
      return <a {...rest} className="text-accent no-underline hover:underline transition-colors duration-200" />;
    },
    // Custom code renderer: handles 'mermaid' blocks and syntax highlighting
    code(props: React.ClassAttributes<HTMLElement> & React.HTMLAttributes<HTMLElement> & ExtraProps) {
      // eslint-disable-next-line @typescript-eslint/no-unused-vars
      const { className, children, node: _node, ...rest } = props;
      const match = /language-(\w+)/.exec(className || '');
      const language = match ? match[1] : '';
      const isMultiLine = String(children).includes('\n');

      // In react-markdown v10, 'inline' prop is removed. 
      // We use className presence (e.g. language-js) or newline presence to detect code blocks.
      if (match || isMultiLine) {
        if (language === 'mermaid') {
          return <Mermaid chart={String(children).replace(/\n$/, '')} />;
        }
        return (
          <CodeBlock language={language} {...rest}>
            {String(children).replace(/\n$/, '')}
          </CodeBlock>
        );
      }

      return (
        <code className={className} {...rest}>
          {children}
        </code>
      );
    },
    // Ensure video elements are responsive and always show controls
    video: (props: React.ClassAttributes<HTMLVideoElement> & React.VideoHTMLAttributes<HTMLVideoElement> & ExtraProps) => {
      // eslint-disable-next-line @typescript-eslint/no-unused-vars
      const { node: _node, width: _w, height: _h, className: _cls, ...rest } = props;
      return (
        <video
          {...rest}
          controls
          className="max-w-full w-full h-auto rounded-lg my-4"
        />
      );
    },
    // Wrap iframes in a 16:9 responsive container (covers YouTube, Vimeo, Bilibili, etc.)
    iframe: (props: React.ClassAttributes<HTMLIFrameElement> & React.IframeHTMLAttributes<HTMLIFrameElement> & ExtraProps) => {
      // eslint-disable-next-line @typescript-eslint/no-unused-vars
      const { node: _node, width: _w, height: _h, className: _cls, ...rest } = props;
      return (
        <div className="relative w-full my-6 rounded-lg overflow-hidden aspect-video">
          <iframe
            {...rest}
            className="absolute inset-0 w-full h-full border-0"
          />
        </div>
      );
    },
    // Ensure images are responsive and styled, using optimized image if dimensions exist
    // In development mode, use unoptimized images since WebP versions don't exist yet
    img: (props: React.ClassAttributes<HTMLImageElement> & React.ImgHTMLAttributes<HTMLImageElement> & ExtraProps) => {
      // eslint-disable-next-line @typescript-eslint/no-unused-vars
      const { src, alt, width, height, node: _node, ...rest } = props;
      const isDev = process.env.NODE_ENV === 'development';
      const imageSrc = src as string;
      const isExternal = imageSrc?.startsWith('http') || imageSrc?.startsWith('//');

      if (!isExternal) {
        return (
          <ExportedImage
            src={imageSrc || ''}
            alt={alt || ''}
            width={width ? Number(width) : 1200}
            height={height ? Number(height) : 900}
            className="max-w-full h-auto rounded-lg my-4"
            sizes="(max-width: 768px) 100vw, (max-width: 1200px) 80vw, 70vw"
            unoptimized={isDev}
            style={(!width || !height) ? { width: '100%', height: 'auto' } : undefined}
          />
        );
      }
      // eslint-disable-next-line @next/next/no-img-element
      return <img src={imageSrc} alt={alt || ''} {...rest} className="max-w-full h-auto rounded-lg my-4" />;
    },
  };

  // Merge custom HTML elements not in the Components type (e.g. web components used in MDX)
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const allComponents = { ...components, 'rss-feed': () => <RssFeedWidget /> } as any;

  return (
    <>
    {latex && <KatexStyles />}
    <div className="prose prose-lg max-w-none min-w-0 overflow-x-hidden text-foreground
          prose-headings:font-serif prose-headings:text-heading 
          prose-p:text-foreground prose-p:leading-loose
          prose-strong:text-heading prose-strong:font-semibold
          prose-code:bg-muted/15 prose-code:px-1.5 prose-code:py-0.5 prose-code:rounded-md prose-code:border prose-code:border-muted/20 prose-code:text-[0.9em] prose-code:font-medium
          prose-code:before:content-none prose-code:after:content-none
          prose-blockquote:italic
          prose-th:text-heading prose-td:text-foreground
          dark:prose-invert">
      <ReactMarkdown
        remarkPlugins={remarkPlugins}
        rehypePlugins={rehypePlugins}
        components={allComponents}
      >
        {content}
      </ReactMarkdown>
    </div>
  );
}

import type { Metadata } from "next";
import localFont from "next/font/local";
import Navbar from "@/components/Navbar";
import Footer from "@/components/Footer";
import Analytics from "@/components/Analytics";
import BrowserDetectionBanner from "@/components/BrowserDetectionBanner";
import { siteConfig } from "../../site.config";
import { ThemeProvider } from "@/components/ThemeProvider";
import { LanguageProvider } from "@/components/LanguageProvider";
import { getAllSeries, getAllBooks, getSeriesData } from "@/lib/markdown";
import { resolveLocale } from "@/lib/i18n";
import "./globals.css";
import "katex/dist/katex.min.css";

const inter = localFont({
  src: [
    {
      path: "../fonts/Inter-Regular.woff2",
      weight: "400",
      style: "normal",
    },
    {
      path: "../fonts/Inter-Bold.woff2",
      weight: "700",
      style: "normal",
    },
  ],
  variable: "--font-inter",
});

const baskerville = localFont({
  src: [
    {
      path: "../fonts/LibreBaskerville-Regular.ttf",
      weight: "400",
      style: "normal",
    },
    {
      path: "../fonts/LibreBaskerville-Bold.ttf",
      weight: "700",
      style: "normal",
    },
    {
      path: "../fonts/LibreBaskerville-Italic.ttf",
      weight: "400",
      style: "italic",
    },
  ],
  variable: "--font-baskerville",
});

const siteTwitterHandle = (() => {
  const url = siteConfig.social?.twitter ?? '';
  const m = url.match(/(?:twitter\.com|x\.com)\/([^/?#]+)/);
  return m ? `@${m[1]}` : undefined;
})();

// Build icon metadata with explicit MIME type so browsers correctly handle
// all formats. Without this, .ico files served via the metadata API lack
// type="image/x-icon" and may be ignored in favour of app/favicon.ico.
const faviconSrc = siteConfig.logo?.favicon || "/icon.svg";
const ext = faviconSrc.split('.').pop()?.toLowerCase();
const faviconMeta =
  ext === 'ico' ? [{ url: faviconSrc, type: 'image/x-icon', sizes: 'any' }] :
  ext === 'png' ? [{ url: faviconSrc, type: 'image/png' }] :
  ext === 'svg' ? [{ url: faviconSrc, type: 'image/svg+xml' }] :
  faviconSrc;

const feedAlternates = (() => {
  const { format } = siteConfig.feed;
  const types: Record<string, string> = {};
  if (format === 'rss' || format === 'both') types['application/rss+xml'] = '/feed.xml';
  if (format === 'atom' || format === 'both') types['application/atom+xml'] = '/feed.atom';
  return Object.keys(types).length > 0 ? { types } : undefined;
})();

export const metadata: Metadata = {
  metadataBase: new URL(siteConfig.baseUrl),
  title: resolveLocale(siteConfig.title),
  description: resolveLocale(siteConfig.description),
  icons: {
    icon: faviconMeta,
  },
  ...(feedAlternates && { alternates: feedAlternates }),
  openGraph: {
    siteName: resolveLocale(siteConfig.title),
    locale: siteConfig.i18n.defaultLocale,
    type: 'website',
    images: [{ url: siteConfig.ogImage, width: 1200, height: 630 }],
  },
  twitter: {
    card: 'summary',
    site: siteTwitterHandle,
    creator: siteTwitterHandle,
  },
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  const features = siteConfig.features;

  // Build series list for navbar (only when series feature is enabled)
  const seriesNavItem = siteConfig.nav.find(item => item.url === '/series');
  const featuredSeries = seriesNavItem?.dropdown;
  let seriesList: { name: string; slug: string }[] = [];
  if (features?.series?.enabled !== false) {
    const allSeries = getAllSeries();
    const seriesKeys = Object.keys(allSeries).sort();
    const filteredKeys = featuredSeries && featuredSeries.length > 0
      ? seriesKeys.filter(slug => featuredSeries.includes(slug))
      : [];
    seriesList = filteredKeys.map(slug => ({
      name: getSeriesData(slug)?.title || allSeries[slug][0]?.series || slug,
      slug,
    }));
  }

  // Build books list for navbar (only when books feature is enabled)
  const booksNavItem = siteConfig.nav.find(item => item.url === '/books');
  const featuredBookSlugs = booksNavItem?.dropdown;
  let booksList: { name: string; slug: string }[] = [];
  if (features?.books?.enabled !== false) {
    const allBooks = getAllBooks();
    booksList = featuredBookSlugs && featuredBookSlugs.length > 0
      ? allBooks
          .filter(book => featuredBookSlugs.includes(book.slug))
          .map(book => ({ name: book.title, slug: book.slug }))
      : [];
  }

  return (
    <html lang={siteConfig.i18n.defaultLocale} suppressHydrationWarning>
      <body
        className={`${inter.variable} ${baskerville.variable} font-sans min-h-screen transition-colors duration-300`}
        data-palette={siteConfig.themeColor}
        suppressHydrationWarning
      >
        {/* Skip to main content link for accessibility */}
        <a
          href="#main-content"
          className="sr-only focus:not-sr-only focus:absolute focus:top-4 focus:left-4 focus:z-[100] focus:px-4 focus:py-2 focus:bg-accent focus:text-white focus:rounded-lg focus:outline-none focus:ring-2 focus:ring-accent focus:ring-offset-2"
        >
          Skip to main content
        </a>
        <ThemeProvider>
          <LanguageProvider>
            <div className="selection:bg-accent/20 selection:text-accent dark:selection:bg-accent/30 dark:selection:text-accent min-h-screen flex flex-col">
              <Navbar seriesList={seriesList} booksList={booksList} />
              <main id="main-content" className="pt-16 flex-grow">
                <BrowserDetectionBanner updateUrl={siteConfig.browserCheck?.updateUrl} />
                {children}
              </main>
              <Footer />
            </div>
            <Analytics />
          </LanguageProvider>
        </ThemeProvider>
      </body>
    </html>
  );
}

